// --- Token Management ---

const (
	signingSecret     = "mesh-internal-secret-key-change-in-production"
	tokenHeader       = "x-mesh-auth-token"
	serviceNameHeader = "x-mesh-service-name"
	requestIDHeader   = "x-mesh-request-id"
	tokenExpiry       = 5 * time.Minute
)

// ServiceToken represents an authentication token for service mesh communication
type ServiceToken struct {
	ServiceName string
	IssuedAt    time.Time
	Signature   string
}

// TokenManager handles token creation and validation
type TokenManager struct {
	secret         []byte
	revokedTokens  map[string]time.Time
	mu             sync.RWMutex
	trustedServices map[string]bool
}

func NewTokenManager(secret string, trustedServices []string) *TokenManager {
	ts := make(map[string]bool)
	for _, s := range trustedServices {
		ts[s] = true
	}
	return &TokenManager{
		secret:          []byte(secret),
		revokedTokens:   make(map[string]time.Time),
		trustedServices: ts,
	}
}

func (tm *TokenManager) GenerateToken(serviceName string) (string, error) {
	tm.mu.RLock()
	if !tm.trustedServices[serviceName] {
		tm.mu.RUnlock()
		return "", fmt.Errorf("service %q is not trusted", serviceName)
	}
	tm.mu.RUnlock()

	issuedAt := time.Now().UTC()
	payload := fmt.Sprintf("%s|%d", serviceName, issuedAt.UnixNano())
	sig := tm.sign(payload)
	token := fmt.Sprintf("%s|%d|%s", serviceName, issuedAt.UnixNano(), sig)
	return token, nil
}

func (tm *TokenManager) ValidateToken(token string) (*ServiceToken, error) {
	parts := strings.SplitN(token, "|", 3)
	if len(parts) != 3 {
		return nil, fmt.Errorf("invalid token format")
	}

	serviceName := parts[0]
	issuedAtNano := parts[1]
	providedSig := parts[2]

	// Check if the service is trusted
	tm.mu.RLock()
	if !tm.trustedServices[serviceName] {
		tm.mu.RUnlock()
		return nil, fmt.Errorf("service %q is not trusted", serviceName)
	}
	tm.mu.RUnlock()

	// Verify signature
	payload := fmt.Sprintf("%s|%s", serviceName, issuedAtNano)
	expectedSig := tm.sign(payload)
	if !hmac.Equal([]byte(providedSig), []byte(expectedSig)) {
		return nil, fmt.Errorf("invalid token signature")
	}

	// Parse and check expiry
	var nanos int64
	_, err := fmt.Sscanf(issuedAtNano, "%d", &nanos)
	if err != nil {
		return nil, fmt.Errorf("invalid timestamp in token")
	}
	issuedAt := time.Unix(0, nanos)
	if time.Since(issuedAt) > tokenExpiry {
		return nil, fmt.Errorf("token expired")
	}

	// Check revocation
	tm.mu.RLock()
	if _, revoked := tm.revokedTokens[token]; revoked {
		tm.mu.RUnlock()
		return nil, fmt.Errorf("token has been revoked")
	}
	tm.mu.RUnlock()

	return &ServiceToken{
		ServiceName: serviceName,
		IssuedAt:    issuedAt,
		Signature:   providedSig,
	}, nil
}

func (tm *TokenManager) RevokeToken(token string) {
	tm.mu.Lock()
	defer tm.mu.Unlock()
	tm.revokedTokens[token] = time.Now()
}

func (tm *TokenManager) CleanupExpiredRevocations() {
	tm.mu.Lock()
	defer tm.mu.Unlock()
	for token, revokedAt := range tm.revokedTokens {
		if time.Since(revokedAt) > tokenExpiry*2 {
			delete(tm.revokedTokens, token)
		}
	}
}

func (tm *TokenManager) sign(payload string) string {
	mac := hmac.New(sha256.New, tm.secret)
	mac.Write([]byte(payload))
	return hex.EncodeToString(mac.Sum(nil))
}

