func authenticate(ctx context.Context, tm *TokenManager) (context.Context, error) {
	md, ok := metadata.FromIncomingContext(ctx)
	if !ok {
		return nil, status.Error(codes.Unauthenticated, "no metadata provided")
	}

	// Extract auth token
	tokens := md.Get(tokenHeader)
	if len(tokens) == 0 {
		return nil, status.Error(codes.Unauthenticated, "no auth token provided")
	}
	authToken := tokens[0]

	// Validate token
	serviceToken, err := tm.ValidateToken(authToken)
	if err != nil {
		return nil, status.Errorf(codes.Unauthenticated, "invalid token: %v", err)
	}

	// Optionally validate the service name header matches the token
	serviceNames := md.Get(serviceNameHeader)
	if len(serviceNames) > 0 && serviceNames[0] != serviceToken.ServiceName {
		return nil, status.Error(codes.Unauthenticated, "service name mismatch")
	}

	// Extract request ID for tracing
	requestID := ""
	requestIDs := md.Get(requestIDHeader)
	if len(requestIDs) > 0 {
		requestID = requestIDs[0]
	}

	// Add authentication info to context
	newCtx := context.WithValue(ctx, contextKeyServiceName, serviceToken.ServiceName)
	newCtx = context.WithValue(newCtx, contextKeyRequestID, requestID)
	newCtx = context.WithValue(newCtx, contextKeyServiceToken, serviceToken)

	return newCtx, nil
}

// Context keys
type contextKey string

const (
	contextKeyServiceName  contextKey = "service_name"
	contextKeyRequestID    contextKey = "request_id"
	contextKeyServiceToken contextKey = "service_token"
)

func ServiceNameFromContext(ctx context.Context) string {
	if v, ok := ctx.Value(contextKeyServiceName).(string); ok {
		return v
	}
	return ""
}

func RequestIDFromContext(ctx context.Context) string {
	if v, ok := ctx.Value(contextKeyRequestID).(string); ok {
		return v
	}
	return ""
}

