// --- Rate Limiting for additional security ---

type RateLimiter struct {
	mu       sync.Mutex
	requests map[string][]time.Time
	limit    int
	window   time.Duration
}

func NewRateLimiter(limit int, window time.Duration) *RateLimiter {
	return &RateLimiter{
		requests: make(map[string][]time.Time),
		limit:    limit,
		window:   window,
	}
}

func (rl *RateLimiter) Allow(serviceName string) bool {
	rl.mu.Lock()
	defer rl.mu.Unlock()

	now := time.Now()
	cutoff := now.Add(-rl.window)

	// Clean old entries
	var valid []time.Time
	for _, t := range rl.requests[serviceName] {
		if t.After(cutoff) {
			valid = append(valid, t)
		}
	}

	if len(valid) >= rl.limit {
		rl.requests[serviceName] = valid
		return false
	}

	rl.requests[serviceName] = append(valid, now)
	return true
}

func RateLimitInterceptor(rl *RateLimiter) grpc.UnaryServerInterceptor {
	return func(
		ctx context.Context,
		req interface{},
		info *grpc.UnaryServerInfo,
		handler grpc.UnaryHandler,
	) (interface{}, error) {
		serviceName := ServiceNameFromContext(ctx)
		if serviceName != "" && !rl.Allow(serviceName) {
			return nil, status.Errorf(codes.ResourceExhausted,
				"rate limit exceeded for service %s", serviceName)
		}
		return handler(ctx, req)
	}
}

// ChainUnaryInterceptors chains multiple unary interceptors
func ChainUnaryInterceptors(interceptors ...grpc.UnaryServerInterceptor) grpc.UnaryServerInterceptor {
	return func(
		ctx context.Context,
		req interface{},
		info *grpc.UnaryServerInfo,
		handler grpc.UnaryHandler,
	) (interface{}, error) {
		chain := handler
		for i := len(interceptors) - 1; i >= 0; i-- {
			currentInterceptor := interceptors[i]
			currentHandler := chain
			chain = func(ctx context.Context, req interface{}) (interface{}, error) {
				return currentInterceptor(ctx, req, info, currentHandler)
			}
		}
		return chain(ctx, req)
	}
}

// --- Logging Interceptor ---

func LoggingInterceptor() grpc.UnaryServerInterceptor {
	return func(
		ctx context.Context,
		req interface{},
		info *grpc.UnaryServerInfo,
		handler grpc.UnaryHandler,
	) (interface{}, error) {
		start := time.Now()
		resp, err := handler(ctx, req)
		duration := time.Since(start)

		serviceName := ServiceNameFromContext(ctx)
		requestID := RequestIDFromContext(ctx)

		if err != nil {
			log.Printf("[%s] %s from=%s duration=%v error=%v",
				requestID, info.FullMethod, serviceName, duration, err)
		} else {
			log.Printf("[%s] %s from=%s duration=%v status=OK",
				requestID, info.FullMethod, serviceName, duration)
		}

		return resp, err
	}
}

