func main() {
	// Define trusted services in the mesh
	trustedServices := []string{
		"api-gateway",
		"user-service",
		"order-service",
		"payment-service",
		"notification-service",
		"inventory-service",
	}

	// Initialize token manager
	tm := NewTokenManager(signingSecret, trustedServices)

	// Start cleanup goroutine for revoked tokens
	go func() {
		ticker := time.NewTicker(1 * time.Minute)
		defer ticker.Stop()
		for range ticker.C {
			tm.CleanupExpiredRevocations()
		}
	}()

	// Initialize rate limiter (100 requests per second per service)
	rl := NewRateLimiter(100, time.Second)

	// Create chained interceptor
	chainedInterceptor := ChainUnaryInterceptors(
		UnaryAuthInterceptor(tm),
		RateLimitInterceptor(rl),
		LoggingInterceptor(),
	)

	// Create gRPC server with interceptors
	server := grpc.NewServer(
		grpc.UnaryInterceptor(chainedInterceptor),
		grpc.StreamInterceptor(StreamAuthInterceptor(tm)),
	)

	// Register service
	meshService := NewMeshServiceServer(tm)
	registerMeshService(server, meshService)

	// Generate sample tokens for demonstration
	log.Println("=== Service Mesh Authentication Server ===")
	log.Println("Generating sample tokens for trusted services:")
	for _, svc := range trustedServices {
		token, err := tm.GenerateToken(svc)
		if err != nil {
			log.Printf("  Failed to generate token for %s: %v", svc, err)
			continue
		}
		log.Printf("  %s: %s", svc, token)
	}

	// Demonstrate token validation
	log.Println("\n--- Token Validation Demo ---")
	testToken, _ := tm.GenerateToken("api-gateway")
	validatedToken, err := tm.ValidateToken(testToken)
	if err != nil {
		log.Printf("Validation failed: %v", err)
	} else {
		log.Printf("Token valid for service: %s, issued at: %s",
			validatedToken.ServiceName, validatedToken.IssuedAt.Format(time.RFC3339Nano))
	}

	// Test untrusted service
	_, err = tm.GenerateToken("malicious-service")
	if err != nil {
		log.Printf("Correctly rejected untrusted service: %v", err)
	}

	// Test token revocation
	revokeToken, _ := tm.GenerateToken("user-service")
	tm.RevokeToken(revokeToken)
	_, err = tm.ValidateToken(revokeToken)
	if err != nil {
		log.Printf("Correctly rejected revoked token: %v", err)
	}

	// Start listening
	port := ":50051"
	lis, err := net.Listen("tcp", port)
	if err != nil {
		log.Fatalf("Failed to listen on %s: %v", port, err)
	}

	log.Printf("\nMesh authentication service listening on %s", port)
	log.Printf("Trusted services: %v", trustedServices)
	log.Printf("Token expiry: %v", tokenExpiry)

	if err := server.Serve(lis); err != nil {
		log.Fatalf("Failed to serve: %v", err)
	}
}